    if a % b == 0:
        return b

    return greatest_common_divisor(b, a % b)

def greatest_common_divisor(a: int, b: int) -> int:
    """ Return a greatest common divisor of two integers a and b
    >>> greatest_common_divisor(3, 5)
    1
    >>> greatest_common_divisor(25, 15)
    5
    """
    if a == b:
        return a

    if a > b:
        greater_number = a
        lesser_number = b
    else:
        greater_number = b
        lesser_number = a

    for i in range(lesser_number, 0, -1):
        if greater_number % i == 0 and lesser_number % i == 0:
            return i
    return 1

