    >>> sort_even([1, 2, 3])
    [1, 2, 3]
    >>> sort_even([5, 6, 3, 4])
    [3, 6, 5, 4]
    """
    l_even, l_odd = [], []
    for i in range(len(l)):
        if i % 2 == 0:
            l_even.append(l[i])
        else:
            l_odd.append(l[i])
    l_even.sort()
    for i in range(len(l_even)):
        l_odd.insert(i * 2, l_even[i])
    return l_odd

